async query(params: QueryParams): Promise<QueryResult> {
  const model = this.selectModel(params)
  const messages = this.assembleMessages(params)
  const tools = this.getAvailableTools(params)

  const stream = await this.callAnthropic({
    model,
    messages,
    tools,
    stream: true
  })

  return this.processStream(stream)
}

function checkContextBudget(
  messages: Message[],
  toolResults: ToolResult[],
  maxTokens: number
): { fits: boolean, overflow: number } {
  const modelTotal = messages.map(m => countTokens(m)).sum()
  const toolsTotal = toolResults.map(t => countTokens(t)).sum()

  const total = modelTotal + toolsTotal
  const overflow = total - maxTokens

  return { fits: overflow <= 0, overflow }
}

async function executeToolLoop(
  engine: QueryEngine,
  messages: Message[]
): Promise<Message> {
  let response = await engine.query(messages)

  while (hasToolCalls(response)) {
    for (const toolCall of response.toolCalls) {
      const result = await toolCall.tool.call(
        toolCall.args,
        engine.context
      )
      messages.push({
        role: 'tool_result',
        content: result
      })
    }
    response = await engine.query(messages)
  }

  return response
}

async function* parseStream(
  response: Response
): AsyncGenerator<string> {
  const reader = response.body.getReader()
  const decoder = new TextDecoder()
  let buffer = ''

  while (true) {
    const { done, value } = await reader.read()
    buffer += decoder.decode(value, { stream: true })

    const lines = buffer.split('\n\n')
    buffer = lines.pop() || ''

    for (const line of lines) {
      if (line.startsWith('data: ')) {
        const data = JSON.parse(line.slice(6))
        if (data.type === 'content_block_delta') {
          yield data.delta.text
        }
      }
    }

    if (done) break
  }
}

const MODEL_PRICING = {
  'claude-opus-4-6': {
    input: 15.0,   // $15 per million input tokens
    output: 75.0  // $75 per million output tokens
  },
  'claude-sonnet-4-6': {
    input: 3.0,
    output: 15.0
  }
}

function calculateCost(
  model: string,
  inputTokens: number,
  outputTokens: number
): number {
  const pricing = MODEL_PRICING[model]
  const inputCost = (inputTokens / 1e6) * pricing.input
  const outputCost = (outputTokens / 1e6) * pricing.output
  return inputCost + outputCost
}

